    payable_id, actual_amount, payment_date, voucher_no, remark, source,
    confirm_user_id, status
) VALUES(
            #{payableId}, #{actualAmount}, #{paymentDate}, #{voucherNo}, #{remark}, #{source},
            #{confirmUserId}, #{status}
        )

mapper.select:
SELECT * FROM payment_record
WHERE payable_id = #{payableId}
ORDER BY payment_date DESC

SELECT * FROM payment_record
WHERE status = #{status}
