mapper.update:
UPDATE payment_record
actual_amount = #{actualAmount}, payment_date = #{paymentDate}, source = #{source}, confirm_user_id = #{confirmUserId}, status = #{status},
WHERE id = #{id}

UPDATE payment_record
SET status = #{status},
    confirm_user_id = #{confirmUserId}
